    // ---- Test 5: Proof composition ----

    #[test]
    fn test_compose_proofs() {
        let checker = ProofChecker::new();

        // Proof 1: liveness for region 1
        let goal1 = Goal::new("liveness", Target::Region(1), ProofContext::new("test1"));
        let mut proof1 = Proof::new(goal1);
        proof1.add_step(ProofStep::Assume {
            fact: Fact::axiom(1, "region 1 is allocated"),
        });
        proof1.add_step(ProofStep::Infer {
            from: vec![1],
            rule: InferenceRule::LivenessIntro,
            conclusion: Fact::derived(2, "region 1 is live"),
        });
        proof1.conclude(Conclusion::Proven);

        // Proof 2: liveness for region 2
        let goal2 = Goal::new("liveness", Target::Region(2), ProofContext::new("test2"));
        let mut proof2 = Proof::new(goal2);
        proof2.add_step(ProofStep::Assume {
            fact: Fact::axiom(1, "region 2 is allocated"),
        });
        proof2.add_step(ProofStep::Infer {
            from: vec![1],
            rule: InferenceRule::LivenessIntro,
            conclusion: Fact::derived(2, "region 2 is live"),
        });
        proof2.conclude(Conclusion::Proven);

        let composed = checker.compose_proofs(&[proof1, proof2]).unwrap();
        assert_eq!(composed.conclusion, Conclusion::Proven);
        // Should have 4 steps (2 from each proof)
        assert_eq!(composed.steps.len(), 4);
    }

    // ---- Test 6: Proof minimization ----

    #[test]
    fn test_minimize_proof() {
        let checker = ProofChecker::new();

        let mut proof = Proof::new(dummy_goal());
        proof.add_step(ProofStep::Assume {
            fact: Fact::axiom(1, "region 1 is allocated"),
        });
        // This fact is never used — should be removed by minimization
        proof.add_step(ProofStep::Assume {
            fact: Fact::axiom(2, "region 99 is allocated (unused)"),
        });
        proof.add_step(ProofStep::Infer {
            from: vec![1],
            rule: InferenceRule::LivenessIntro,
            conclusion: Fact::derived(3, "region 1 is live"),
        });
        proof.conclude(Conclusion::Proven);

        let minimized = checker.minimize_proof(&proof);
        assert!(minimized.steps.len() < proof.steps.len());
        assert_eq!(minimized.steps.len(), 2); // fact 1 + infer, fact 2 removed
        assert_eq!(minimized.conclusion, Conclusion::Proven);
    }

    // ---- Test 7: IVE proof obligation conversion ----

    #[test]
    fn test_ive_proof_obligation_conversion() {
        let obligations = vec![
            IVEProofObligation::ExclusivityObligation {
                access1: 1,
                access2: 2,
                obligation_kind: "data_race".into(),
                resolution: "lock_based".into(),
            },
            IVEProofObligation::InterpretationObligation {
                location: 42,
                from_bd: "i32".into(),
                to_bd: "u32".into(),
                cast_kind: "same_size".into(),
            },
            IVEProofObligation::LivenessObligation {
                region: 5,
                obligation_kind: "use_after_free".into(),
            },
            IVEProofObligation::OriginObligation {
                derivation: 10,
                obligation_kind: "dangling".into(),
            },
            IVEProofObligation::CleanupObligation {
                resource: 7,
                obligation_kind: "leak".into(),
            },
        ];

        // Test kind_name
        assert_eq!(obligations[0].kind_name(), "exclusivity");
        assert_eq!(obligations[1].kind_name(), "interpretation");
        assert_eq!(obligations[2].kind_name(), "liveness");
        assert_eq!(obligations[3].kind_name(), "origin");
        assert_eq!(obligations[4].kind_name(), "cleanup");

        // Test to_goal conversion
        let goal0 = obligations[0].to_goal();
        assert_eq!(goal0.invariant, "exclusivity");
        assert_eq!(goal0.target, Target::Access(1));

        let goal1 = obligations[1].to_goal();
        assert_eq!(goal1.invariant, "interpretation");
        assert_eq!(goal1.target, Target::Derivation(42));

        let goal2 = obligations[2].to_goal();
        assert_eq!(goal2.invariant, "liveness");
        assert_eq!(goal2.target, Target::Region(5));

        let goal3 = obligations[3].to_goal();
        assert_eq!(goal3.invariant, "origin");
        assert_eq!(goal3.target, Target::Derivation(10));

        let goal4 = obligations[4].to_goal();
        assert_eq!(goal4.invariant, "cleanup");
        assert_eq!(goal4.target, Target::Region(7));

        // Test Display
        assert!(format!("{}", obligations[0]).contains("exclusivity"));
        assert!(format!("{}", obligations[1]).contains("interpretation"));
        assert!(format!("{}", obligations[2]).contains("liveness"));
        assert!(format!("{}", obligations[3]).contains("origin"));
        assert!(format!("{}", obligations[4]).contains("cleanup"));
    }

