    // ---- Additional test: minimization with no redundant steps ----

    #[test]
    fn test_minimize_proof_no_redundancy() {
        let checker = ProofChecker::new();

        let mut proof = Proof::new(dummy_goal());
        proof.add_step(ProofStep::Assume {
            fact: Fact::axiom(1, "region 1 is allocated"),
        });
        proof.add_step(ProofStep::Infer {
            from: vec![1],
            rule: InferenceRule::LivenessIntro,
            conclusion: Fact::derived(2, "region 1 is live"),
        });
        proof.conclude(Conclusion::Proven);

        let minimized = checker.minimize_proof(&proof);
        assert_eq!(minimized.steps.len(), proof.steps.len());
    }

    // ---- Additional test: PartiallyProved variant ----

    #[test]
    fn test_partially_proved_result() {
        let result: AutoProofResult = AutoProofResult::PartiallyProved {
            proof: Proof::new(Goal::new("test", Target::Region(1), ProofContext::new("test"))),
            remaining_obligations: vec![IVEProofObligation::LivenessObligation {
                region: 2,
                obligation_kind: "use_after_free".into(),
            }],
        };

        match result {
            AutoProofResult::PartiallyProved { remaining_obligations, .. } => {
                assert_eq!(remaining_obligations.len(), 1);
            }
            other => panic!("expected PartiallyProved, got {:?}", other),
        }
    }
